CREATE TABLE users (id TEXT PRIMARY KEY, name TEXT NOT NULL, free_chips INTEGER DEFAULT 1000, vip BOOLEAN DEFAULT FALSE, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE sponsors (id TEXT PRIMARY KEY, name TEXT NOT NULL, status TEXT NOT NULL, budget_cents INTEGER NOT NULL DEFAULT 0);
CREATE TABLE tournaments (id TEXT PRIMARY KEY, name TEXT NOT NULL, sponsor_id TEXT REFERENCES sponsors(id), entry_fee_cents INTEGER DEFAULT 0, rebuy_cents INTEGER DEFAULT 0, prize_cents INTEGER NOT NULL, prize_source TEXT NOT NULL, uses_player_funds BOOLEAN DEFAULT FALSE, allows_chip_cashout BOOLEAN DEFAULT FALSE, status TEXT NOT NULL, rules_version TEXT NOT NULL);
CREATE TABLE tournament_entries (tournament_id TEXT REFERENCES tournaments(id), user_id TEXT REFERENCES users(id), accepted_rules_version TEXT, entered_at TIMESTAMPTZ DEFAULT now(), PRIMARY KEY(tournament_id,user_id));
CREATE TABLE leagues (id TEXT PRIMARY KEY, name TEXT NOT NULL, season TEXT NOT NULL, sponsor_id TEXT REFERENCES sponsors(id), prize_cents INTEGER DEFAULT 0, prize_source TEXT DEFAULT 'SPONSOR', status TEXT NOT NULL);
CREATE TABLE leaderboard_entries (league_id TEXT REFERENCES leagues(id), user_id TEXT REFERENCES users(id), xp INTEGER DEFAULT 0, wins INTEGER DEFAULT 0, PRIMARY KEY(league_id,user_id));
CREATE TABLE purchases (id BIGSERIAL PRIMARY KEY, user_id TEXT REFERENCES users(id), item_id TEXT NOT NULL, price_cents INTEGER NOT NULL, affects_prize BOOLEAN DEFAULT FALSE, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE admin_audit_log (id BIGSERIAL PRIMARY KEY, actor_id TEXT, action TEXT NOT NULL, payload JSONB, created_at TIMESTAMPTZ DEFAULT now());
